<?php
namespace Tests\Feature;use App\Models\Employee;use App\Models\PayrollItem;use App\Models\PayrollRun;use App\Models\Role;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Laravel\Sanctum\Sanctum;use Tests\TestCase;
class PayslipPdfTest extends TestCase{use RefreshDatabase;public function test_employee_can_download_released_own_payslip_pdf():void{$role=Role::create(['name'=>'Employee','slug'=>'employee','permissions'=>['payroll.self'],'is_active'=>true]);$user=User::factory()->create(['role_id'=>$role->id,'employee_id'=>'E001','is_active'=>true]);$employee=Employee::create(['user_id'=>$user->id,'joining_date'=>now(),'employment_type'=>'full-time','salary'=>50000]);$run=PayrollRun::create(['name'=>'July 2026','period_start'=>'2026-07-01','period_end'=>'2026-07-31','payment_date'=>'2026-08-05','status'=>'paid','created_by'=>$user->id]);$item=PayrollItem::create(['payroll_run_id'=>$run->id,'employee_id'=>$employee->id,'gross_earnings'=>50000,'net_pay'=>45000,'earnings'=>['BASIC'=>50000],'deductions'=>['TAX'=>5000]]);Sanctum::actingAs($user);$this->get("/api/payslips/{$item->id}/pdf")->assertOk()->assertHeader('Content-Type','application/pdf');}}
